{
  "name": "Infoproduct Hub",
  "description": "Uma plataforma completa para venda e consumo de infoprodutos com catálogo, checkout transparente e área de membros exclusiva."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Category {
  EBOOK = 'Ebook',
  COURSE = 'Curso',
  SUBSCRIPTION = 'Assinatura'
}

export interface Product {
  id: string;
  title: string;
  description: string;
  price: number;
  category: Category;
  imageUrl: string;
  contentCount?: number; // e.g., "12 aulas" or "45 páginas"
}

export interface User {
  id: string;
  name: string;
  email: string;
  purchasedIds: string[];
  subscriptionActive: boolean;
}

export interface Lesson {
  id: string;
  title: string;
  duration: string;
  videoUrl?: string;
  locked?: boolean;
}

import React, { createContext, useContext, useState, useCallback, ReactNode } from 'react';
import { User } from '../types';

interface AuthContextType {
  user: User | null;
  isLoggedIn: boolean;
  login: () => void;
  logout: () => void;
  hasAccess: (productId: string) => boolean;
  purchaseProduct: (productId: string) => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);

  const login = useCallback(() => {
    // Simulated login
    setUser({
      id: 'u123',
      name: 'João Silva',
      email: 'joao@exemplo.com',
      purchasedIds: ['2'], // User already owns the Ebook (id: 2)
      subscriptionActive: true
    });
  }, []);

  const logout = useCallback(() => {
    setUser(null);
  }, []);

  const hasAccess = useCallback((productId: string) => {
    if (!user) return false;
    return user.purchasedIds.includes(productId);
  }, [user]);

  const purchaseProduct = useCallback((productId: string) => {
    if (!user) return;
    setUser(prev => prev ? ({
      ...prev,
      purchasedIds: [...new Set([...prev.purchasedIds, productId])]
    }) : null);
  }, [user]);

  return (
    <AuthContext.Provider value={{ user, isLoggedIn: !!user, login, logout, hasAccess, purchaseProduct }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within AuthProvider');
  return context;
};

import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Navbar: React.FC = () => {
  const { isLoggedIn, user, login, logout } = useAuth();
  const navigate = useNavigate();

  return (
    <nav className="bg-white border-b border-slate-200 sticky top-0 z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-16 items-center">
          <div className="flex items-center space-x-8">
            <Link to="/" className="text-2xl font-bold text-indigo-600">InfoHub</Link>
            <div className="hidden md:flex space-x-4">
              <Link to="/" className="text-slate-600 hover:text-indigo-600 px-3 py-2 font-medium">Catálogo</Link>
              {isLoggedIn && (
                <Link to="/dashboard" className="text-slate-600 hover:text-indigo-600 px-3 py-2 font-medium">Meus Produtos</Link>
              )}
            </div>
          </div>

          <div className="flex items-center space-x-4">
            {isLoggedIn ? (
