              >
                Entrar
              </button>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

import React from 'react';
import { useNavigate } from 'react-router-dom';
import { Product, Category } from '../types';
import { useAuth } from '../context/AuthContext';

interface ProductCardProps {
  product: Product;
}

const ProductCard: React.FC<ProductCardProps> = ({ product }) => {
  const { hasAccess, isLoggedIn, login } = useAuth();
  const navigate = useNavigate();
  const owned = hasAccess(product.id);

  const handleAction = () => {
    if (!isLoggedIn) {
      login();
      return;
    }

    if (owned) {
      if (product.category === Category.COURSE) {
        navigate(`/members/${product.id}`);
      } else {
        navigate('/dashboard');
      }
    } else {
      navigate(`/checkout/${product.id}`);
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col hover:shadow-md transition-shadow">
      <div className="relative h-48">
        <img 
          src={product.imageUrl} 
          alt={product.title} 
          className="w-full h-full object-cover"
        />
        <div className="absolute top-2 right-2">
          <span className={`px-2 py-1 text-xs font-semibold rounded-full ${
            product.category === Category.COURSE ? 'bg-blue-100 text-blue-700' :
            product.category === Category.EBOOK ? 'bg-green-100 text-green-700' :
            'bg-purple-100 text-purple-700'
          }`}>
            {product.category}
          </span>
        </div>
      </div>

      <div className="p-5 flex-1 flex flex-col">
        <h3 className="text-lg font-bold text-slate-900 mb-2">{product.title}</h3>
        <p className="text-slate-600 text-sm line-clamp-2 mb-4 flex-1">{product.description}</p>

        <div className="flex items-center justify-between mt-auto pt-4 border-t border-slate-50">
          <div>
            {!owned && (
              <span className="text-xl font-bold text-slate-900">
                R$ {product.price.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
              </span>
            )}
            {owned && (
              <span className="text-sm font-medium text-emerald-600 flex items-center">
                <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7" />
                </svg>
                Adquirido
              </span>
            )}
          </div>

          <button 
            onClick={handleAction}
            className={`px-4 py-2 rounded-lg text-sm font-semibold transition-colors ${
              owned 
                ? 'bg-slate-100 text-slate-900 hover:bg-slate-200' 
                : 'bg-indigo-600 text-white hover:bg-indigo-700'
            }`}
          >
            {owned ? 'Acessar Conteúdo' : 'Comprar Agora'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default ProductCard;

import React, { useEffect } from 'react';
import { Navigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

interface ProtectedRouteProps {
  children: React.ReactNode;
}

const ProtectedRoute: React.FC<ProtectedRouteProps> = ({ children }) => {
  const { isLoggedIn, login } = useAuth();
  const location = useLocation();

  if (!isLoggedIn) {
    // We could automatically trigger login or redirect to a landing page
    return <Navigate to="/" state={{ from: location }} replace />;
  }

  return <>{children}</>;
};

export default ProtectedRoute;

import React from 'react';
import { Link } from 'react-router-dom';

