              <p className="text-slate-500 text-sm line-clamp-2">{product.description}</p>
              <div className="mt-2 text-indigo-600 font-bold">R$ {product.price.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</div>
            </div>
          </div>

          <div className="mt-8 grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="p-4 bg-slate-100 rounded-xl flex items-center space-x-3">
              <div className="bg-white p-2 rounded-lg text-indigo-600">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" />
                </svg>
              </div>
              <span className="text-sm font-semibold text-slate-700">Acesso Imediato</span>
            </div>
            <div className="p-4 bg-slate-100 rounded-xl flex items-center space-x-3">
              <div className="bg-white p-2 rounded-lg text-indigo-600">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04rem" />
                </svg>
              </div>
              <span className="text-sm font-semibold text-slate-700">7 Dias de Garantia</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Checkout;

