import React from 'react';
import { useNavigate } from 'react-router-dom';
import { Product, Category } from '../types';
import { useAuth } from '../context/AuthContext';

interface ProductCardProps {
  product: Product;
}

const ProductCard: React.FC<ProductCardProps> = ({ product }) => {
  const { hasAccess, isLoggedIn, login } = useAuth();
  const navigate = useNavigate();
  const owned = hasAccess(product.id);

  const handleAction = () => {
    if (!isLoggedIn) {
      login();
      return;
    }
    if (owned) {
      navigate(product.category === Category.COURSE ? `/members/${product.id}` : '/dashboard');
    } else {
      navigate(`/checkout/${product.id}`);
    }
  };

  return (
    <div 
      onClick={handleAction}
      className="group relative cursor-pointer transform transition-all duration-300 hover:scale-110 hover:z-20"
    >
      <div className="aspect-[16/9] rounded-sm overflow-hidden bg-slate-800">
