import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { MOCK_PRODUCTS } from '../constants';
import { useAuth } from '../context/AuthContext';

const Checkout: React.FC = () => {
  const { id } = useParams();
  const { purchaseProduct, user } = useAuth();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);

  const product = MOCK_PRODUCTS.find(p => p.id === id);

  useEffect(() => {
    if (!product) navigate('/');
  }, [product, navigate]);

  const handlePayment = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setTimeout(() => {
      setLoading(false);
      setSuccess(true);
      purchaseProduct(product!.id);
    }, 2000);
  };

  if (success) {
    return (
      <div className="min-h-screen flex items-center justify-center px-4">
        <div className="max-w-md w-full text-center">
          <div className="bg-emerald-500/20 w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-8 border border-emerald-500">
            <svg className="w-12 h-12 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" />
            </svg>
          </div>
          <h2 className="text-4xl font-black mb-4">Acesso Liberado!</h2>
          <p className="text-slate-400 text-lg mb-10">Prepare a pipoca. Seu novo conteúdo está pronto para ser maratonado.</p>
          <button 
            onClick={() => navigate('/dashboard')}
            className="w-full bg-white text-black py-4 rounded font-black hover:bg-slate-200 transition-all shadow-xl"
          >
            Começar a Assistir
          </button>
        </div>
      </div>
    );
  }

  if (!product) return null;

  return (
    <div className="max-w-6xl mx-auto px-4 py-32">
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-20">
        <div>
          <h2 className="text-4xl font-black mb-10 tracking-tight">Assinar Agora</h2>
          <form onSubmit={handlePayment} className="space-y-6">
            <div className="bg-[#222] p-8 rounded-md border border-white/5 space-y-6">
