                <button onClick={login} className="text-slate-700 font-semibold text-sm hover:text-indigo-600 transition-colors">Entrar</button>
                <button onClick={login} className="bg-indigo-600 text-white px-5 py-2 rounded-full text-sm font-bold hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100">Criar conta</button>
              </>
            ) : (
