                <div className="flex items-center space-x-2 cursor-pointer" onClick={() => navigate('/dashboard')}>
                   <div className="w-9 h-9 bg-slate-100 rounded-full flex items-center justify-center border border-slate-200">
                     <span className="text-indigo-600 font-bold text-xs">{user?.name.charAt(0)}</span>
                   </div>
                   <span className="text-sm font-medium text-slate-700 hidden sm:inline">{user?.name}</span>
                </div>
                <button onClick={() => { logout(); navigate('/'); }} className="text-slate-400 hover:text-rose-500 transition-colors">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
};

