import React from 'react';
import { Module, Lesson } from '../types';

interface CurriculumBuilderProps {
  modules: Module[];
  onChange: (modules: Module[]) => void;
}

const CurriculumBuilder: React.FC<CurriculumBuilderProps> = ({ modules, onChange }) => {

  const addModule = () => {
    const newModule: Module = {
      id: Math.random().toString(36).substr(2, 9),
      title: 'Novo Módulo',
      lessons: []
    };
    onChange([...modules, newModule]);
  };

  const updateModuleTitle = (moduleId: string, title: string) => {
    onChange(modules.map(m => m.id === moduleId ? { ...m, title } : m));
  };

  const addLesson = (moduleId: string) => {
    const newLesson: Lesson = {
      id: Math.random().toString(36).substr(2, 9),
      title: 'Nova Aula',
      duration: '00:00',
      locked: true
    };
    onChange(modules.map(m => m.id === moduleId ? { ...m, lessons: [...m.lessons, newLesson] } : m));
  };

  const deleteModule = (moduleId: string) => {
    onChange(modules.filter(m => m.id !== moduleId));
  };

  const updateLesson = (moduleId: string, lessonId: string, updates: Partial<Lesson>) => {
    onChange(modules.map(m => m.id === moduleId ? {
      ...m,
      lessons: m.lessons.map(l => l.id === lessonId ? { ...l, ...updates } : l)
    } : m));
  };

  return (
    <div className="space-y-6">
      {modules.map((module, mIdx) => (
        <div key={module.id} className="bg-slate-50 border border-slate-200 rounded-xl overflow-hidden">
          <div className="p-4 bg-white border-b border-slate-200 flex items-center justify-between group">
            <div className="flex items-center flex-1 space-x-4">
              <span className="text-slate-400 font-bold">M{mIdx + 1}</span>
              <input 
                type="text" 
                value={module.title}
                onChange={(e) => updateModuleTitle(module.id, e.target.value)}
                className="bg-transparent font-bold text-slate-800 outline-none focus:ring-2 focus:ring-indigo-100 rounded px-2 py-1 flex-1"
              />
            </div>
            <button onClick={() => deleteModule(module.id)} className="text-slate-300 hover:text-rose-500 p-1 opacity-0 group-hover:opacity-100 transition-opacity">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
            </button>
          </div>

          <div className="p-4 space-y-3">
            {module.lessons.map((lesson, lIdx) => (
              <div key={lesson.id} className="bg-white border border-slate-200 p-3 rounded-lg flex items-center space-x-4 shadow-sm">
                <div className="w-8 h-8 rounded-lg bg-indigo-50 flex items-center justify-center text-xs font-bold text-indigo-600">
                  {lIdx + 1}
                </div>
                <input 
                  type="text" 
                  placeholder="Título da Aula"
                  value={lesson.title}
                  onChange={(e) => updateLesson(module.id, lesson.id, { title: e.target.value })}
                  className="flex-1 text-sm font-medium text-slate-700 outline-none"
                />
                <input 
                  type="text" 
                  placeholder="URL do Vídeo"
                  value={lesson.videoUrl || ''}
                  onChange={(e) => updateLesson(module.id, lesson.id, { videoUrl: e.target.value })}
                  className="w-32 text-xs text-slate-400 outline-none border-b border-slate-100 focus:border-indigo-300"
                />
                <div className="flex items-center space-x-2">
                   <button onClick={() => updateLesson(module.id, lesson.id, { locked: !lesson.locked })} className={`p-1 rounded ${lesson.locked ? 'text-slate-300' : 'text-emerald-500'}`}>
                     {lesson.locked ? (
                       <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M5 9V7a5 5 0 0110 0v2a2 2 0 012 2v5a2 2 0 01-2 2H5a2 2 0 01-2-2v-5a2 2 0 012-2zm8-2v2H7V7a3 3 0 016 0z" clipRule="evenodd" /></svg>
                     ) : (
                       <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 11V7a4 4 0 118 0m-4 8v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2z" /></svg>
                     )}
                   </button>
                </div>
              </div>
            ))}

            <button 
              onClick={() => addLesson(module.id)}
              className="w-full py-2 border-2 border-dashed border-slate-200 rounded-lg text-slate-400 text-xs font-bold hover:border-indigo-200 hover:text-indigo-400 transition-all flex items-center justify-center"
            >
              <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
              Adicionar Aula
            </button>
          </div>
        </div>
      ))}

      <button 
        onClick={addModule}
        className="w-full py-4 bg-white border-2 border-indigo-600 border-dashed rounded-xl text-indigo-600 font-bold hover:bg-indigo-50 transition-all flex items-center justify-center"
      >
        <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
        Novo Módulo
      </button>
    </div>
  );
};

export default CurriculumBuilder;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Category, Module } from '../types';
import CurriculumBuilder from '../components/CurriculumBuilder';

const CreateProduct: React.FC = () => {
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);

  // Form State
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    category: Category.COURSE,
    price: 0,
    pricingType: 'one-time', // one-time | subscription
    image: null as File | null,
    ebookFile: null as File | null,
    modules: [] as Module[]
  });

  const handleNext = () => setStep(s => s + 1);
  const handleBack = () => setStep(s => s - 1);

  const handleSubmit = async () => {
    setLoading(true);

    // Logic differentiation for Payload
    const payload = {
      title: formData.title,
      description: formData.description,
      category: formData.category,
      price: formData.price,
      pricingType: formData.pricingType,
    };

    if (formData.category === Category.COURSE) {
      Object.assign(payload, { curriculum: formData.modules });
      console.log('Enviando Curso para API:', payload);
    } else if (formData.category === Category.EBOOK) {
      Object.assign(payload, { fileId: 'simulated-file-id' });
      console.log('Enviando Ebook para API:', payload);
    } else {
      console.log('Enviando Assinatura para API:', payload);
    }

    // Simulate API call
    setTimeout(() => {
      setLoading(false);
      navigate('/producer');
    }, 2000);
  };

  const steps = [
    { n: 1, label: 'Básico' },
    { n: 2, label: 'Preço' },
    { n: 3, label: 'Conteúdo' }
  ];

  return (
    <div className="max-w-4xl mx-auto px-4 py-12">
      <div className="mb-10">
        <button onClick={() => navigate('/producer')} className="text-sm font-bold text-slate-400 hover:text-indigo-600 flex items-center mb-6">
          <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
          Voltar ao Painel
        </button>
        <h1 className="text-3xl font-black text-slate-900">Criar Novo Infoproduto</h1>
      </div>

      {/* Progress Stepper */}
      <div className="flex items-center justify-between mb-12 relative">
        <div className="absolute left-0 top-1/2 -translate-y-1/2 h-0.5 w-full bg-slate-200"></div>
        {steps.map(s => (
          <div key={s.n} className="relative z-10 flex flex-col items-center">
            <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold transition-all ${
              step >= s.n ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white border-2 border-slate-200 text-slate-300'
            }`}>
              {s.n}
            </div>
            <span className={`text-[10px] font-black uppercase tracking-widest mt-2 ${step >= s.n ? 'text-indigo-600' : 'text-slate-300'}`}>
              {s.label}
            </span>
          </div>
        ))}
      </div>

      {/* Step Content */}
      <div className="bg-white rounded-2xl border border-slate-200 p-8 shadow-sm">
        {step === 1 && (
          <div className="space-y-6">
            <h2 className="text-xl font-bold text-slate-800">Informações Básicas</h2>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Nome do Produto *</label>
              <input 
                type="text" 
                value={formData.title}
                onChange={e => setFormData({ ...formData, title: e.target.value })}
                className="w-full p-3 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-100" 
                placeholder="Ex: Dominando Next.js"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Descrição Curta *</label>
              <textarea 
                value={formData.description}
                onChange={e => setFormData({ ...formData, description: e.target.value })}
                className="w-full p-3 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-100 h-24" 
                placeholder="Resuma seu produto em poucas palavras..."
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Categoria</label>
              <div className="grid grid-cols-3 gap-4">
                {[Category.COURSE, Category.EBOOK, Category.SUBSCRIPTION].map(cat => (
                  <button 
                    key={cat}
                    onClick={() => setFormData({ ...formData, category: cat })}
                    className={`p-4 rounded-xl border-2 font-bold text-sm transition-all ${
                      formData.category === cat ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-slate-100 text-slate-500'
                    }`}
                  >
                    {cat}
                  </button>
                ))}
              </div>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6">
            <h2 className="text-xl font-bold text-slate-800">Configuração de Preço</h2>
            <div className="grid grid-cols-2 gap-6">
              <div 
                onClick={() => setFormData({ ...formData, pricingType: 'one-time' })}
                className={`p-6 rounded-2xl border-2 cursor-pointer transition-all ${formData.pricingType === 'one-time' ? 'border-indigo-600 bg-indigo-50' : 'border-slate-100'}`}
              >
                <div className="w-10 h-10 bg-white rounded-lg flex items-center justify-center mb-4 shadow-sm">💳</div>
                <h4 className="font-bold text-slate-800">Pagamento Único</h4>
                <p className="text-xs text-slate-500">O aluno paga uma vez e tem acesso conforme sua regra.</p>
              </div>
              <div 
                onClick={() => setFormData({ ...formData, pricingType: 'subscription' })}
                className={`p-6 rounded-2xl border-2 cursor-pointer transition-all ${formData.pricingType === 'subscription' ? 'border-indigo-600 bg-indigo-50' : 'border-slate-100'}`}
              >
                <div className="w-10 h-10 bg-white rounded-lg flex items-center justify-center mb-4 shadow-sm">🔄</div>
                <h4 className="font-bold text-slate-800">Assinatura Recorrente</h4>
                <p className="text-xs text-slate-500">Pagamentos mensais, trimestrais ou anuais.</p>
              </div>
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Valor de Venda (BRL)</label>
              <div className="relative">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold">R$</span>
                <input 
                  type="number" 
                  value={formData.price}
                  onChange={e => setFormData({ ...formData, price: parseFloat(e.target.value) })}
                  className="w-full pl-12 p-3 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-100" 
                  placeholder="0,00"
                />
              </div>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6">
            <h2 className="text-xl font-bold text-slate-800">Conteúdo do {formData.category}</h2>

            {formData.category === Category.EBOOK && (
              <div className="border-2 border-dashed border-slate-200 rounded-2xl p-12 text-center">
                <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                  <svg className="w-8 h-8 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
                </div>
                <h4 className="font-bold text-slate-700">Faça o upload do seu Ebook (PDF)</h4>
                <p className="text-xs text-slate-400 mb-6">Tamanho máximo de 50MB</p>
                <input type="file" id="ebook" className="hidden" accept=".pdf" />
                <label htmlFor="ebook" className="cursor-pointer bg-slate-900 text-white px-6 py-2 rounded-lg text-sm font-bold">Escolher arquivo</label>
              </div>
            )}

            {formData.category === Category.COURSE && (
              <CurriculumBuilder 
                modules={formData.modules} 
                onChange={(modules) => setFormData({ ...formData, modules })} 
              />
            )}

            {formData.category === Category.SUBSCRIPTION && (
              <div className="p-8 bg-indigo-50 border border-indigo-100 rounded-2xl text-center">
                 <p className="text-indigo-700 font-medium">Para assinaturas, o conteúdo é gerenciado através da área de membros e mentorias agendadas.</p>
              </div>
            )}
          </div>
        )}

        {/* Action Buttons */}
        <div className="flex justify-between items-center mt-12 pt-8 border-t border-slate-100">
          <button 
            onClick={step === 1 ? () => navigate('/producer') : handleBack}
            className="text-slate-400 font-bold hover:text-slate-600 transition-colors"
          >
            {step === 1 ? 'Cancelar' : 'Voltar'}
          </button>

          {step < 3 ? (
            <button 
              onClick={handleNext}
              className="bg-indigo-600 text-white px-10 py-3 rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100"
            >
              Continuar
            </button>
          ) : (
            <button 
              onClick={handleSubmit}
              disabled={loading}
              className="bg-emerald-600 text-white px-10 py-3 rounded-xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-100 disabled:opacity-50"
            >
              {loading ? 'Finalizando...' : 'Publicar Produto'}
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

