                </div>
                <button onClick={() => { logout(); navigate('/'); }} className="text-slate-400 hover:text-rose-500 transition-colors">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

import React, { useState, useMemo } from 'react';
import { useLocation } from 'react-router-dom';
import { MOCK_PRODUCTS } from '../constants';
import { Category, Product } from '../types';
import ProductCard from '../components/ProductCard';
import FeaturedSlider from '../components/FeaturedSlider';
import Offcanvas from '../components/Offcanvas';

const Catalog: React.FC = () => {
  const [quickViewProduct, setQuickViewProduct] = useState<Product | null>(null);
  const [filter, setFilter] = useState<Category | 'Todos'>('Todos');
  const location = useLocation();

  const searchQuery = new URLSearchParams(location.search).get('q') || '';

  const filtered = useMemo(() => {
    return MOCK_PRODUCTS.filter(p => {
      const matchesCategory = filter === 'Todos' || p.category === filter;
      const matchesSearch = p.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
                          p.description.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [filter, searchQuery]);

  return (
    <div className="max-w-7xl mx-auto px-4 py-12">
      {/* Esconde o slider se estiver pesquisando algo específico */}
      {!searchQuery && (
        <section className="mb-20">
          <FeaturedSlider />
        </section>
      )}

      <section className="mb-12">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
          <div>
            {searchQuery ? (
              <h2 className="text-2xl font-black text-slate-900 mb-2">
                Resultados para "<span className="text-indigo-600">{searchQuery}</span>"
              </h2>
            ) : (
              <>
                <h2 className="text-3xl font-black text-slate-900 mb-2 italic">Novidades fresquinhas</h2>
                <p className="text-slate-500">Explore o que há de melhor no aprendizado online.</p>
              </>
            )}
          </div>

          <div className="flex overflow-x-auto pb-2 md:pb-0 space-x-2">
            {['Todos', Category.COURSE, Category.EBOOK, Category.SUBSCRIPTION].map(cat => (
              <button
                key={cat}
                onClick={() => setFilter(cat as any)}
                className={`px-6 py-2 rounded-full text-sm font-bold whitespace-nowrap transition-all ${
                  filter === cat 
                    ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' 
                    : 'bg-white text-slate-600 border border-slate-200 hover:border-indigo-300'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>

        {filtered.length > 0 ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
            {filtered.map(product => (
              <ProductCard 
                key={product.id} 
                product={product} 
                onQuickView={(p) => setQuickViewProduct(p)}
              />
            ))}
          </div>
        ) : (
          <div className="py-20 text-center">
             <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-6">
                <svg className="w-10 h-10 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
             </div>
             <h3 className="text-xl font-bold text-slate-800">Nenhum resultado encontrado</h3>
             <p className="text-slate-500 mt-2">Tente buscar por termos diferentes ou explore as categorias.</p>
             <button 
                onClick={() => window.location.href = '#/'}
                className="mt-6 text-indigo-600 font-bold hover:underline"
              >
               Limpar busca e ver tudo
             </button>
          </div>
        )}
      </section>

      {!searchQuery && (
        <section className="bg-indigo-900 rounded-3xl p-12 text-center text-white relative overflow-hidden shadow-2xl">
          <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-500 rounded-full blur-[100px] opacity-20 -mr-32 -mt-32"></div>
          <div className="relative z-10">
              <h2 className="text-4xl font-black mb-6">Pronto para transformar sua carreira?</h2>
              <p className="text-indigo-200 mb-10 text-lg max-w-2xl mx-auto">Junte-se a mais de 50.000 alunos que já mudaram de vida com nossos conteúdos exclusivos e práticos.</p>
              <button className="bg-white text-indigo-900 px-10 py-4 rounded-2xl font-black hover:bg-slate-100 transition-all shadow-xl">
                Começar Agora
              </button>
          </div>
        </section>
      )}

      <Offcanvas product={quickViewProduct} onClose={() => setQuickViewProduct(null)} />
    </div>
  );
};

export default Catalog;

import React, { useState, useEffect } from 'react';
import { MOCK_PRODUCTS } from '../constants';
import { useNavigate } from 'react-router-dom';

const FeaturedSlider: React.FC = () => {
  const [current, setCurrent] = useState(0);
  const [isAnimating, setIsAnimating] = useState(false);
  const navigate = useNavigate();
  const featured = MOCK_PRODUCTS.slice(0, 3);

  const next = () => {
    if (isAnimating) return;
    setIsAnimating(true);
    setCurrent((current + 1) % featured.length);
  };

  const prev = () => {
    if (isAnimating) return;
    setIsAnimating(true);
    setCurrent((current - 1 + featured.length) % featured.length);
  };

  useEffect(() => {
    const timer = setTimeout(() => setIsAnimating(false), 800);
    return () => clearTimeout(timer);
  }, [current]);

  // Auto-play
  useEffect(() => {
    const interval = setInterval(next, 8000);
    return () => clearInterval(interval);
  }, [current]);

  return (
    <div className="relative w-full h-[500px] md:h-[600px] bg-slate-950 overflow-hidden rounded-[2rem] group shadow-2xl">
      {/* Background Mesh Gradients */}
      <div className="absolute inset-0 z-0">
        <div className={`absolute top-[-10%] right-[-10%] w-[50%] h-[50%] rounded-full bg-indigo-600/20 blur-[120px] transition-opacity duration-1000 ${current === 0 ? 'opacity-100' : 'opacity-0'}`}></div>
        <div className={`absolute bottom-[-10%] left-[-10%] w-[50%] h-[50%] rounded-full bg-emerald-600/10 blur-[120px] transition-opacity duration-1000 ${current === 1 ? 'opacity-100' : 'opacity-0'}`}></div>
        <div className={`absolute top-[20%] left-[10%] w-[40%] h-[40%] rounded-full bg-rose-600/10 blur-[120px] transition-opacity duration-1000 ${current === 2 ? 'opacity-100' : 'opacity-0'}`}></div>
      </div>

      {featured.map((item, index) => (
        <div 
          key={item.id}
          className={`absolute inset-0 transition-all duration-1000 ease-in-out flex items-center ${
            index === current ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'
          }`}
        >
          {/* Main Image Overlay */}
          <div className="absolute inset-0 z-0">
            <img 
              src={item.imageUrl} 
              className={`w-full h-full object-cover opacity-20 scale-110 transition-transform duration-[10s] ease-linear ${index === current ? 'scale-100' : 'scale-110'}`} 
              alt="" 
            />
            <div className="absolute inset-0 bg-gradient-to-r from-slate-950 via-slate-950/80 to-transparent"></div>
          </div>

          <div className="relative z-10 w-full max-w-7xl mx-auto px-8 md:px-20 grid grid-cols-1 lg:grid-cols-2 gap-12 items-center">
            {/* Left Content */}
            <div className={`transition-all duration-700 delay-300 ${index === current ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0'}`}>
              <div className="flex items-center space-x-3 mb-6">
                <span className="bg-indigo-600 text-white text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-[0.2em] shadow-lg shadow-indigo-500/30">
                  Best Seller
                </span>
                <div className="flex items-center bg-white/10 backdrop-blur-md px-3 py-1 rounded-full border border-white/10">
                  <div className="flex -space-x-2 mr-3">
                    {[1,2,3].map(i => (
                      <div key={i} className="w-5 h-5 rounded-full border-2 border-slate-900 bg-slate-700 overflow-hidden">
                        <img src={`https://i.pravatar.cc/100?u=student${i}`} alt="" />
                      </div>
                    ))}
                  </div>
                  <span className="text-[10px] font-bold text-indigo-200">+4.5k Alunos</span>
                </div>
              </div>

              <h2 className="text-5xl md:text-7xl font-black text-white mb-6 leading-[1.1] tracking-tight">
                {item.title}
              </h2>

              <p className="text-slate-400 text-lg md:text-xl mb-10 line-clamp-2 max-w-xl leading-relaxed">
                {item.description} Domine as estratégias que os 1% usam para obter resultados fora da curva.
              </p>

              <div className="flex flex-wrap items-center gap-6">
                <button 
                  onClick={() => navigate(`/product/${item.id}`)}
                  className="bg-white text-slate-950 px-10 py-4 rounded-2xl font-black text-lg hover:bg-indigo-50 transition-all transform hover:scale-105 active:scale-95 shadow-[0_20px_40px_rgba(255,255,255,0.1)]"
                >
                  Garantir minha vaga
                </button>
                <div className="flex flex-col">
                  <span className="text-indigo-400 text-[10px] font-black uppercase tracking-widest">Apenas hoje</span>
                  <span className="text-white font-black text-3xl italic tracking-tighter">R$ {item.price.toFixed(2)}</span>
                </div>
              </div>
            </div>

            {/* Right Content - Visual Mockup */}
            <div className={`hidden lg:block relative transition-all duration-1000 delay-500 ${index === current ? 'translate-x-0 opacity-100 scale-100' : 'translate-x-20 opacity-0 scale-90'}`}>
               <div className="relative w-full aspect-square max-w-md mx-auto group-hover:rotate-1 transition-transform duration-500">
                  {/* Glass Card Backdrop */}
                  <div className="absolute inset-0 bg-gradient-to-br from-white/10 to-transparent backdrop-blur-3xl rounded-[2.5rem] border border-white/10 shadow-2xl"></div>

                  {/* Floating Image */}
                  <div className="absolute inset-4 rounded-[2rem] overflow-hidden shadow-2xl animate-float">
                    <img src={item.imageUrl} className="w-full h-full object-cover" alt="" />
                    <div className="absolute inset-0 bg-gradient-to-t from-slate-950/60 to-transparent"></div>
                    <div className="absolute bottom-6 left-6 right-6">
                       <div className="bg-white/90 backdrop-blur p-4 rounded-xl shadow-lg flex items-center justify-between">
                          <div>
                            <p className="text-slate-900 font-black text-sm">Aula de Destaque</p>
                            <p className="text-slate-500 text-[10px] font-bold">Conteúdo em 4K disponível</p>
                          </div>
                          <div className="w-10 h-10 bg-indigo-600 rounded-full flex items-center justify-center text-white shadow-lg shadow-indigo-200">
                             <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
                          </div>
                       </div>
                    </div>
                  </div>

                  {/* Decorative Elements */}
                  <div className="absolute -top-6 -right-6 w-24 h-24 bg-indigo-500/20 rounded-full blur-2xl animate-pulse"></div>
                  <div className="absolute -bottom-10 -left-10 w-32 h-32 bg-emerald-500/20 rounded-full blur-3xl animate-pulse"></div>
               </div>
            </div>
          </div>
        </div>
      ))}

      {/* Modern Controls */}
      <div className="absolute bottom-10 left-8 md:left-20 z-20 flex items-center space-x-8">
        <div className="flex space-x-2">
          {featured.map((_, i) => (
            <button 
              key={i} 
              onClick={() => setCurrent(i)}
              className={`h-1.5 rounded-full transition-all duration-500 ${i === current ? 'w-12 bg-indigo-500 shadow-[0_0_15px_rgba(99,102,241,0.5)]' : 'w-3 bg-white/20 hover:bg-white/40'}`}
            ></button>
          ))}
        </div>
        <div className="flex space-x-3">
          <button 
            onClick={prev} 
            className="w-12 h-12 bg-white/5 hover:bg-white/10 border border-white/10 rounded-2xl flex items-center justify-center text-white transition-all backdrop-blur-sm"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 19l-7-7 7-7" /></svg>
          </button>
          <button 
            onClick={next} 
            className="w-12 h-12 bg-white/5 hover:bg-white/10 border border-white/10 rounded-2xl flex items-center justify-center text-white transition-all backdrop-blur-sm"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 5l7 7-7 7" /></svg>
          </button>
        </div>
      </div>

      <style dangerouslySetInnerHTML={{ __html: `
        @keyframes float {
          0% { transform: translateY(0px); }
          50% { transform: translateY(-15px); }
          100% { transform: translateY(0px); }
        }
        .animate-float {
          animation: float 6s ease-in-out infinite;
        }
      `}} />
    </div>
  );
};

export default FeaturedSlider;
